mapper.select:
SELECT p.partner_id AS partnerId, TO_CHAR(r.check_out_date, 'YYYY-MM') AS settlementMonth,
/* 총 결제액: 실결제액 합산 */ SUM(o.real_total_amount) AS totalSales,
/* 수수료: reservation.commission_rate 적용 후 합산 */ SUM(ROUND(o.real_total_amount * p.commission_rate / 100)) AS commissionAmount,
/* 최종 지급액 */ SUM(o.real_total_amount) - SUM(ROUND(o.real_total_amount * p.commission_rate / 100)) AS netAmount
FROM reservation r JOIN room rm ON rm.room_id = r.room_id JOIN place pl ON pl.place_id = rm.place_id JOIN partner p ON p.partner_id = pl.partner_id JOIN order_detail od ON od.reservation_id = r.reservation_id JOIN orders o ON o.order_id = od.order_id
WHERE r.status = 'SUCCESS'
AND r.check_out_date < TRUNC(SYSDATE) AND o.status != 'CANCELED' AND p.partner_id IS NOT NULL AND p.status = 1
/* 핵심: 이미 집계된 파트너+월 조합은 제외 (done 포함) 승인 완료된 건 배치가 건드리지 않음 */ AND NOT EXISTS ( SELECT 1 FROM partner_settlement ps WHERE ps.partner_id = p.partner_id AND ps.settlement_month = TO_CHAR(r.check_out_date, 'YYYY-MM') )
GROUP BY p.partner_id, TO_CHAR(r.check_out_date, 'YYYY-MM')
ORDER BY settlementMonth, partnerId

SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM partner_settlement
WHERE partner_id       = #{partnerId}
  AND settlement_month = #{settlementMonth}

mapper.update:
UPDATE partner_settlement
SET total_sales       = total_sales       + #{totalSales},
    commission_amount = commission_amount + #{commissionAmount},
    net_amount        = net_amount        + #{netAmount}
WHERE partner_id       = #{partnerId}
  AND settlement_month = #{settlementMonth}
  AND status          != 'done'
